const raw = $json.output;
const chunks = raw.split('},');

const prompts = chunks.map(chunk => {
  return chunk         
    .replace(/```/g, '')          
    .replace(/json/g, '')        
    .replace(/\\nA/g, ' ') 
    .replace(/"prompt":\s*/gi, '') 
    .replace(/\\n/g, ' ')         
    .replace(/[{}\[\]"]/g, '')
    .replace(/^\s*\n*\n*\n*A\s*/i, "")
    .trim();
}).filter(p => p.length > 0);

return prompts.map(prompt => ({
  json: { prompt }
}));

let raw = $input.first().json.output;
const jsonMatch = raw.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error("No valid JSON object found in the output.");
}

const cleanRaw = jsonMatch[0];
const data = JSON.parse(cleanRaw);

return [
  {
    json: {
      filename: data["Adobe Stock"].Filename,
      title: data["Adobe Stock"].Title,
      keywords: data["Adobe Stock"].Keywords,
      category_adobe: data["Adobe Stock"].Category,
      releases: data["Adobe Stock"].Releases,

      description_shutterstock: data["Shutterstock"].Description,
      category_shutterstock: data["Shutterstock"].Categories,
      editorial: data["Shutterstock"].Editorial,
      mature_content: data["Shutterstock"].Mature_Content,
      illustration: data["Shutterstock"].Illustration
    }
  }
];
